  2565→bool ConnectionManagerImpl::shouldDeferRequestProxyingToNextIoCycle() {
  2566→  // Do not defer this stream if stream deferral is disabled
  2567→  if (deferred_request_processing_callback_ == nullptr) {
  2568→    return false;
  2569→  }
  2570→  // Defer this stream if there are already deferred streams, so they are not
  2571→  // processed out of order
  2572→  if (deferred_request_processing_callback_->enabled()) {
  2573→    return true;
  2574→  }
  2575→  ++requests_during_dispatch_count_;
  2576→  bool defer = requests_during_dispatch_count_ > max_requests_during_dispatch_;
  2577→  if (defer) {
